"use client";

import { loadFont } from "@remotion/google-fonts/JetBrainsMono";
import {
  AbsoluteFill,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { Caret } from "@/components/remocn/caret";
import { useTypewriter } from "@/lib/remocn-ui";

const { fontFamily: MONO_FAMILY } = loadFont();

export interface ClaudeCodeProps {
  title?: string;
  userName?: string;
  model?: string;
  cwd?: string;
  placeholder?: string;
  prompt?: string;
  accentColor?: string;
  speed?: number;
  /**
   * When true, the prompt is "submitted" after it finishes typing and the CLI
   * enters a thinking phase — a pulsing status line (spinner + cycling verb +
   * elapsed/token counters) over a stream of activity lines. Off by default so
   * existing usage of the welcome screen is unchanged.
   */
  thinking?: boolean;
  /**
   * Effective frame at which the thinking phase begins. Defaults to just after
   * the typewriter finishes (derived from `prompt`, `TYPING_START_FRAME` and
   * `TYPING_CPS`).
   */
  thinkingStartFrame?: number;
  /** Status verbs cycled in the thinking line (one every ~0.8s). */
  thinkingVerbs?: string[];
  /** Activity lines streamed in one-by-one beneath the status line. */
  thinkingActivity?: string[];
  /** Frames between each streamed activity line. */
  thinkingLineStagger?: number;
}

interface Theme {
  page: string;
  windowBar: string;
  windowBody: string;
  fg: string;
  fgMuted: string;
  fgDim: string;
  boxBorder: string;
}

export const THEMES: Record<"light" | "dark", Theme> = {
  light: {
    page: "#E8E5DD",
    windowBar: "#D8D3CA",
    windowBody: "#FBFAF7",
    fg: "#1F1E1D",
    fgMuted: "#73726C",
    fgDim: "#A3A097",
    boxBorder: "#D97757",
  },
  dark: {
    page: "#2B2A28",
    windowBar: "#3A3633",
    windowBody: "#1B1A18",
    fg: "#E8E5DD",
    fgMuted: "#8A857C",
    fgDim: "#6B6660",
    boxBorder: "#D97757",
  },
};

export const TYPING_START_FRAME = 48;

export const TYPING_CPS = 18;

export const WHATS_NEW: string[] = [
  "/agents to create subagents",
  "/security-review for review agent",
  "ctrl+b to background bashes",
];

// Pulsing star used by the thinking status line — cycles outward then back so
// it "breathes" in place rather than spinning.
const THINKING_GLYPHS = ["·", "✢", "✳", "✶", "✺", "✶", "✳", "✢"];

export const DEFAULT_THINKING_VERBS: string[] = [
  "Thinking",
  "Composing",
  "Animating",
  "Rendering",
  "Polishing",
];

export const DEFAULT_THINKING_ACTIVITY: string[] = [
  "Loading skill: remocn",
  "Reading components catalog",
  "Composing scenes — backdrop, titles, code",
  "Wiring kinetic transitions",
  "✓ Created the composition",
];

/** Format a token count as Claude Code does: "1.2k". */
function formatTokens(n: number): string {
  if (n < 1000) return String(Math.round(n));
  return `${(n / 1000).toFixed(1)}k`;
}

function introBounceIn(
  frame: number,
  fps: number,
): { translateY: number; scale: number } {
  const s = spring({
    fps,
    frame,
    config: { damping: 14, stiffness: 110, mass: 0.7 },
  });
  const translateY = interpolate(s, [0, 1], [28, 0]);
  const scale = interpolate(s, [0, 1], [0.97, 1]);
  return { translateY, scale };
}

function fadeUpAt(
  frame: number,
  range: [number, number],
): { opacity: number; translateY: number } {
  const opts = {
    extrapolateLeft: "clamp" as const,
    extrapolateRight: "clamp" as const,
  };
  return {
    opacity: interpolate(frame, range, [0, 1], opts),
    translateY: interpolate(frame, range, [12, 0], opts),
  };
}

function Mascot({ accent, size = 96 }: { accent: string; size?: number }) {
  return (
    <svg
      height={size}
      viewBox="0 0 24 24"
      width={size}
      xmlns="http://www.w3.org/2000/svg"
    >
      <title>Claude Code</title>
      <path
        clipRule="evenodd"
        d="M20.998 10.949H24v3.102h-3v3.028h-1.487V20H18v-2.921h-1.487V20H15v-2.921H9V20H7.488v-2.921H6V20H4.487v-2.921H3V14.05H0V10.95h3V5h17.998v5.949zM6 10.949h1.488V8.102H6v2.847zm10.51 0H18V8.102h-1.49v2.847z"
        fill={accent}
        fillRule="evenodd"
      />
    </svg>
  );
}

interface ThinkingStreamProps {
  /** Effective frames elapsed since the thinking phase began (>= 0). */
  local: number;
  fps: number;
  prompt: string;
  accentColor: string;
  theme: Theme;
  verbs: string[];
  activity: string[];
  lineStagger: number;
}

function ThinkingStream({
  local,
  fps,
  prompt,
  accentColor,
  theme,
  verbs,
  activity,
  lineStagger,
}: ThinkingStreamProps) {
  const glyph = THINKING_GLYPHS[Math.floor(local / 4) % THINKING_GLYPHS.length];
  const verb = verbs[Math.floor(local / 24) % verbs.length];
  const seconds = Math.max(0, Math.floor(local / fps));
  // Tokens ramp up smoothly while thinking, easing toward a plausible total.
  const tokens = formatTokens(interpolate(local, [0, 150], [120, 3400], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  }));

  return (
    <div style={{ fontFamily: MONO_FAMILY }}>
      {/* The submitted command, echoed back as a sent message. */}
      <div
        style={{
          display: "flex",
          flexDirection: "row",
          alignItems: "center",
          fontSize: 17,
          whiteSpace: "pre",
          color: theme.fg,
        }}
      >
        <span style={{ color: theme.fgMuted }}>{"> "}</span>
        {prompt}
      </div>

      {/* Status line: breathing star + cycling verb + meta. */}
      <div
        style={{
          display: "flex",
          flexDirection: "row",
          alignItems: "center",
          gap: 10,
          marginTop: 18,
          fontSize: 16,
          whiteSpace: "pre",
        }}
      >
        <span style={{ color: accentColor, width: 14, display: "inline-block" }}>
          {glyph}
        </span>
        <span style={{ color: theme.fg }}>{verb}…</span>
        <span style={{ color: theme.fgDim }}>
          {`(esc to interrupt · ${seconds}s · ↑ ${tokens} tokens)`}
        </span>
      </div>

      {/* Streamed activity lines, each fading up as it arrives. */}
      <div
        style={{
          marginTop: 14,
          display: "flex",
          flexDirection: "column",
          gap: 8,
        }}
      >
        {activity.map((line, i) => {
          const at = (i + 1) * lineStagger;
          const fade = fadeUpAt(local, [at, at + 14]);
          const done = line.trimStart().startsWith("✓");
          return (
            <div
              key={line}
              style={{
                display: "flex",
                flexDirection: "row",
                alignItems: "center",
                gap: 8,
                fontSize: 14,
                whiteSpace: "pre",
                opacity: fade.opacity,
                transform: `translateY(${fade.translateY}px)`,
              }}
            >
              <span style={{ color: done ? "#28C840" : accentColor }}>
                {done ? "⎿  " : "⎿  "}
              </span>
              <span style={{ color: done ? theme.fg : theme.fgMuted }}>
                {line}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}

export function ClaudeCode({
  title = "Claude Code v2.0.0",
  userName = "Meaghan",
  model = "Opus 4.8 • Max 20x",
  cwd = "/users/meaghan/code/apps",
  placeholder = 'Try "edit <filepath> to ..."',
  prompt = "edit src/theme.ts to add a dark mode toggle",
  accentColor = "#D97757",
  speed = 1,
  thinking = false,
  thinkingStartFrame,
  thinkingVerbs = DEFAULT_THINKING_VERBS,
  thinkingActivity = DEFAULT_THINKING_ACTIVITY,
  thinkingLineStagger = 22,
}: ClaudeCodeProps) {
  const frame = useCurrentFrame();
  const { width, height, fps } = useVideoConfig();
  const t = THEMES.dark;

  const refW = 1280;
  const refH = 720;
  const stageScale = Math.min(width / refW, height / refH);

  const tw = useTypewriter(prompt, {
    cps: TYPING_CPS,
    speed,
    startFrame: TYPING_START_FRAME,
  });
  const showText = tw.count > 0;

  // Effective (speed-adjusted) frame, and when the thinking phase kicks in —
  // by default right after the typewriter finishes the prompt.
  const effFrame = frame * speed;
  const typingDoneFrame =
    TYPING_START_FRAME + (prompt.length / TYPING_CPS) * fps;
  const thinkStart = thinkingStartFrame ?? typingDoneFrame + 12;
  const isThinking = thinking && effFrame >= thinkStart;
  // Once thinking begins, fade the welcome box back so the stream is the focus.
  const welcomeDim = thinking
    ? interpolate(effFrame, [thinkStart, thinkStart + 16], [1, 0.22], {
        extrapolateLeft: "clamp",
        extrapolateRight: "clamp",
      })
    : 1;

  const intro = introBounceIn(frame * speed, fps);
  const leftFade = fadeUpAt(frame * speed, [6, 22]);
  const rightFade = fadeUpAt(frame * speed, [12, 30]);
  const promptFade = fadeUpAt(frame * speed, [18, 36]);

  const border = accentColor;

  const winLeft = 90;
  const winTop = 40;
  const winWidth = 1100;
  const winHeight = 620;
  const barHeight = 40;

  return (
    <AbsoluteFill style={{ background: "transparent" }}>
      <div
        style={{
          position: "absolute",
          left: "50%",
          top: "50%",
          width: refW,
          height: refH,
          transform: `translate(-50%, -50%) scale(${stageScale})`,
        }}
      >
        <div
          style={{
            position: "absolute",
            left: winLeft,
            top: winTop,
            width: winWidth,
            height: winHeight,
            background: t.windowBody,
            borderRadius: 12,
            overflow: "hidden",
            boxShadow: "0 24px 60px -20px rgba(0,0,0,0.6)",
            opacity: intro.scale,
            transform: `translateY(${intro.translateY}px) scale(${intro.scale})`,
            transformOrigin: "center top",
            display: "flex",
            flexDirection: "column",
            boxSizing: "border-box",
          }}
        >
          <div
            style={{
              height: barHeight,
              background: t.windowBar,
              display: "flex",
              alignItems: "center",
              gap: 8,
              paddingLeft: 16,
              flexShrink: 0,
            }}
          >
            <div
              style={{
                width: 12,
                height: 12,
                borderRadius: "50%",
                background: "#FF5F57",
              }}
            />
            <div
              style={{
                width: 12,
                height: 12,
                borderRadius: "50%",
                background: "#FEBC2E",
              }}
            />
            <div
              style={{
                width: 12,
                height: 12,
                borderRadius: "50%",
                background: "#28C840",
              }}
            />
          </div>

          <div
            style={{
              flex: 1,
              position: "relative",
              padding: 28,
              boxSizing: "border-box",
              display: "flex",
              flexDirection: "column",
            }}
          >
            <div
              style={{
                position: "relative",
                border: `1px dashed ${border}`,
                borderRadius: 6,
                padding: "28px 24px 24px",
                opacity: leftFade.opacity * welcomeDim,
                transform: `translateY(${leftFade.translateY}px)`,
              }}
            >
              <span
                style={{
                  position: "absolute",
                  top: -11,
                  left: 22,
                  padding: "0 10px",
                  background: t.windowBody,
                  color: accentColor,
                  fontFamily: MONO_FAMILY,
                  fontSize: 16,
                  fontWeight: 700,
                }}
              >
                {title}
              </span>

              <div style={{ display: "flex", flexDirection: "row" }}>
                <div
                  style={{
                    width: "42%",
                    display: "flex",
                    flexDirection: "column",
                    alignItems: "flex-start",
                    gap: 16,
                    paddingRight: 24,
                    boxSizing: "border-box",
                  }}
                >
                  <div
                    style={{
                      fontFamily: MONO_FAMILY,
                      fontSize: 20,
                      color: t.fg,
                    }}
                  >
                    Welcome back {userName}!
                  </div>
                  <div style={{ alignSelf: "center" }}>
                    <Mascot accent={accentColor} />
                  </div>
                  <div
                    style={{
                      display: "flex",
                      flexDirection: "column",
                      gap: 4,
                    }}
                  >
                    <div
                      style={{
                        fontFamily: MONO_FAMILY,
                        fontSize: 15,
                        color: t.fgMuted,
                      }}
                    >
                      {model}
                    </div>
                    <div
                      style={{
                        fontFamily: MONO_FAMILY,
                        fontSize: 15,
                        color: t.fgMuted,
                      }}
                    >
                      {cwd}
                    </div>
                  </div>
                </div>

                <div
                  style={{
                    width: "58%",
                    borderLeft: `1px dashed ${border}`,
                    paddingLeft: 24,
                    boxSizing: "border-box",
                    display: "flex",
                    flexDirection: "column",
                    opacity: rightFade.opacity,
                    transform: `translateY(${rightFade.translateY}px)`,
                  }}
                >
                  <div>
                    <div
                      style={{
                        fontFamily: MONO_FAMILY,
                        fontSize: 15,
                        fontWeight: 700,
                        color: accentColor,
                        marginBottom: 10,
                      }}
                    >
                      What's new
                    </div>
                    <div
                      style={{
                        display: "flex",
                        flexDirection: "column",
                        gap: 6,
                      }}
                    >
                      {WHATS_NEW.map((line) => (
                        <div
                          key={line}
                          style={{
                            fontFamily: MONO_FAMILY,
                            fontSize: 14,
                            color: t.fg,
                          }}
                        >
                          {line}
                        </div>
                      ))}
                      <div
                        style={{
                          fontFamily: MONO_FAMILY,
                          fontSize: 14,
                          color: t.fgDim,
                        }}
                      >
                        ... /help for more
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            </div>

            <div style={{ height: 32 }} />

            <div
              style={{
                opacity: promptFade.opacity,
                transform: `translateY(${promptFade.translateY}px)`,
              }}
            >
              <div
                style={{
                  height: 1,
                  background: t.fgDim,
                  opacity: 0.4,
                  marginBottom: 16,
                }}
              />
              {isThinking ? (
                <ThinkingStream
                  local={effFrame - thinkStart}
                  fps={fps}
                  prompt={prompt}
                  accentColor={accentColor}
                  theme={t}
                  verbs={thinkingVerbs}
                  activity={thinkingActivity}
                  lineStagger={thinkingLineStagger}
                />
              ) : (
              <div
                style={{
                  display: "flex",
                  flexDirection: "row",
                  alignItems: "center",
                  fontFamily: MONO_FAMILY,
                  fontSize: 17,
                  whiteSpace: "pre",
                }}
              >
                <span style={{ color: t.fgMuted }}>{"> "}</span>
                {showText ? (
                  <span
                    style={{
                      position: "relative",
                      color: t.fg,
                      display: "inline-flex",
                      alignItems: "center",
                    }}
                  >
                    {tw.text}
                    <span style={{ opacity: 0.55, display: "inline-flex" }}>
                      <Caret
                        width={11}
                        height={22}
                        color={t.fg}
                        blink={!tw.typing}
                        speed={speed}
                        marginLeft={2}
                      />
                    </span>
                  </span>
                ) : (
                  <span
                    style={{
                      position: "relative",
                      color: t.fgMuted,
                      display: "inline-flex",
                      alignItems: "center",
                    }}
                  >
                    <span style={{ opacity: 0.55, display: "inline-flex" }}>
                      <Caret
                        width={11}
                        height={22}
                        color={t.fg}
                        blink={!tw.typing}
                        speed={speed}
                      />
                    </span>
                    <span style={{ marginLeft: 6 }}>{placeholder}</span>
                  </span>
                )}
              </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </AbsoluteFill>
  );
}

"use client";

import {
  Sequence,
  interpolate,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";

export interface GlassCodeBlockProps {
  code?: string;
  title?: string;
  width?: number;
  height?: number;
  fontSize?: number;
  glassColor?: string;
  staggerFrames?: number;
  showTrafficLights?: boolean;
  /** The soft cyan/purple gradient glow behind the glass. On by default. */
  aura?: boolean;
  /**
   * Reveal the first line as a left-to-right typewriter (with a block cursor)
   * instead of the default fade-up; the remaining lines then stagger in only
   * after the first line finishes typing. Off by default.
   */
  typeFirstLine?: boolean;
  /** Typing speed (characters/second) when `typeFirstLine` is on. */
  firstLineCps?: number;
  speed?: number;
  className?: string;
}

/** Frames the first-line typewriter takes — exported so a caller can sync a
 *  camera move to the moment typing completes. */
export function firstLineTypeFrames(
  firstLine: string,
  firstLineCps: number,
  fps: number,
): number {
  return Math.ceil((firstLine.length / firstLineCps) * fps);
}

const FONT_MONO =
  "var(--font-geist-mono), ui-monospace, SFMono-Regular, monospace";

const DEFAULT_CODE = `import { motion } from "remotion";

// Generate a hero scene
export function Hero() {
  const frame = useCurrentFrame();
  const opacity = frame / 30;
  return <h1 style={{ opacity }}>Hello</h1>;
}`;

// Minimal regex tokenizer. NOT a real syntax highlighter — just enough to
// give the eye color anchors. Order matters: comments → strings → keywords.
const KEYWORDS = new Set([
  "import",
  "from",
  "export",
  "function",
  "const",
  "let",
  "var",
  "return",
  "if",
  "else",
  "for",
  "while",
  "new",
  "class",
  "extends",
  "default",
  "true",
  "false",
  "null",
  "undefined",
]);

type Token = {
  text: string;
  kind: "code" | "comment" | "string" | "keyword" | "number";
};

function tokenizeLine(line: string): Token[] {
  // Whole-line comment.
  const trimmed = line.trimStart();
  if (trimmed.startsWith("//")) {
    return [{ text: line, kind: "comment" }];
  }

  const tokens: Token[] = [];
  // Split keeping delimiters: words, strings, numbers, everything else.
  const re = /("[^"]*"|'[^']*'|`[^`]*`|\b\d+\b|\b[A-Za-z_$][\w$]*\b|[^\w"']+)/g;
  let match: RegExpExecArray | null;
  while ((match = re.exec(line)) !== null) {
    const t = match[0];
    const first = t[0];
    if (first === '"' || first === "'" || first === "`") {
      tokens.push({ text: t, kind: "string" });
    } else if (/^\d+$/.test(t)) {
      tokens.push({ text: t, kind: "number" });
    } else if (/^[A-Za-z_$][\w$]*$/.test(t) && KEYWORDS.has(t)) {
      tokens.push({ text: t, kind: "keyword" });
    } else {
      tokens.push({ text: t, kind: "code" });
    }
  }
  return tokens;
}

const TOKEN_COLORS: Record<Token["kind"], string> = {
  code: "#e4e4e7",
  comment: "#52525b",
  string: "#86efac",
  keyword: "#c4b5fd",
  number: "#fcd34d",
};

export function GlassCodeBlock({
  code = DEFAULT_CODE,
  title = "hero.tsx",
  width = 760,
  height = 460,
  fontSize = 16,
  glassColor = "rgba(10, 10, 10, 0.6)",
  staggerFrames = 4,
  showTrafficLights = true,
  aura = true,
  typeFirstLine = false,
  firstLineCps = 30,
  speed = 1,
  className,
}: GlassCodeBlockProps) {
  const { fps } = useVideoConfig();
  const lines = code.split("\n");
  // When the first line types, every later line waits until typing is done.
  const typeDur = typeFirstLine
    ? firstLineTypeFrames(lines[0] ?? "", firstLineCps, fps)
    : 0;

  return (
    <div
      className={className}
      style={{
        position: "absolute",
        inset: 0,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      {/* Animated background hint behind the glass so the blur has something
          to chew on. Pure CSS — no extra deps. */}
      {aura && <BackdropAura />}

      {/* 1px gradient ring acting as a microborder */}
      <div
        style={{
          position: "relative",
          padding: 1,
          borderRadius: 16,
          background:
            "linear-gradient(180deg, rgba(255,255,255,0.18) 0%, rgba(255,255,255,0) 100%)",
          width,
          height,
          boxShadow: "0 50px 120px rgba(0,0,0,0.55)",
        }}
      >
        <div
          style={{
            width: "100%",
            height: "100%",
            borderRadius: 15,
            background: glassColor,
            backdropFilter: "blur(16px)",
            WebkitBackdropFilter: "blur(16px)",
            boxShadow: "inset 0 1px 0 rgba(255,255,255,0.06)",
            display: "flex",
            flexDirection: "column",
            overflow: "hidden",
            fontFamily: FONT_MONO,
          }}
        >
          {/* Chrome */}
          <div
            style={{
              height: 40,
              display: "flex",
              alignItems: "center",
              gap: 8,
              padding: "0 16px",
              borderBottom: "1px solid rgba(255,255,255,0.06)",
            }}
          >
            {showTrafficLights && (
              <>
                <Light color="#ff5f57" />
                <Light color="#febc2e" />
                <Light color="#28c840" />
              </>
            )}
            <div
              style={{
                flex: 1,
                textAlign: "center",
                color: "#a1a1aa",
                fontSize: 12,
                letterSpacing: "0.02em",
              }}
            >
              {title}
            </div>
          </div>

          {/* Code body */}
          <div
            style={{
              flex: 1,
              padding: "20px 24px",
              display: "flex",
              flexDirection: "column",
              gap: 4,
              fontSize,
              lineHeight: 1.55,
            }}
          >
            {lines.map((line, i) => {
              if (typeFirstLine && i === 0) {
                return (
                  <Sequence key={i} from={0} layout="none">
                    <TypedCodeLine
                      line={line}
                      index={i}
                      fontSize={fontSize}
                      cps={firstLineCps}
                      fps={fps}
                      speed={speed}
                    />
                  </Sequence>
                );
              }
              const baseFrom = typeFirstLine
                ? typeDur + (i - 1) * staggerFrames
                : i * staggerFrames;
              return (
                <Sequence
                  key={i}
                  from={Math.round(baseFrom / speed)}
                  layout="none"
                >
                  <CodeLine line={line} index={i} fontSize={fontSize} />
                </Sequence>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
}

function Light({ color }: { color: string }) {
  return (
    <div
      style={{
        width: 12,
        height: 12,
        borderRadius: "50%",
        background: color,
        opacity: 0.6,
      }}
    />
  );
}

function CodeLine({
  line,
  index,
  fontSize,
}: {
  line: string;
  index: number;
  fontSize: number;
}) {
  const frame = useCurrentFrame();
  const opacity = interpolate(frame, [0, 8], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });
  const ty = interpolate(frame, [0, 8], [4, 0], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  const tokens = tokenizeLine(line);
  // Render an empty line as a half-height spacer so blank lines still take
  // visual space without collapsing the gap.
  if (tokens.length === 0) {
    return <div style={{ height: fontSize * 0.8, opacity }} />;
  }
  return (
    <div
      style={{
        opacity,
        transform: `translateY(${ty}px)`,
        whiteSpace: "pre",
        display: "flex",
        gap: 0,
      }}
    >
      <span style={{ width: 28, color: "#3f3f46", userSelect: "none" }}>
        {String(index + 1).padStart(2, " ")}
      </span>
      <span>
        {tokens.map((t, i) => (
          <span key={i} style={{ color: TOKEN_COLORS[t.kind] }}>
            {t.text}
          </span>
        ))}
      </span>
    </div>
  );
}

function TypedCodeLine({
  line,
  index,
  fontSize,
  cps,
  fps,
  speed,
}: {
  line: string;
  index: number;
  fontSize: number;
  cps: number;
  fps: number;
  speed: number;
}) {
  const frame = useCurrentFrame() * speed;
  const len = line.length;
  const revealed = Math.floor(
    interpolate(frame, [0, (len / cps) * fps], [0, len], {
      extrapolateLeft: "clamp",
      extrapolateRight: "clamp",
    }),
  );
  const visible = line.substring(0, revealed);
  const done = revealed >= len;
  // 2 Hz blink at any framerate.
  const cursorOn = Math.floor((frame / fps) * 2) % 2 === 0;
  const tokens = tokenizeLine(visible);

  return (
    <div
      style={{
        whiteSpace: "pre",
        display: "flex",
        gap: 0,
        alignItems: "center",
      }}
    >
      <span style={{ width: 28, color: "#3f3f46", userSelect: "none" }}>
        {String(index + 1).padStart(2, " ")}
      </span>
      <span>
        {tokens.map((t, i) => (
          <span key={i} style={{ color: TOKEN_COLORS[t.kind] }}>
            {t.text}
          </span>
        ))}
        {!done && cursorOn && (
          <span
            style={{
              display: "inline-block",
              width: fontSize * 0.55,
              height: fontSize,
              background: "#e4e4e7",
              marginLeft: 1,
              transform: "translateY(2px)",
            }}
          />
        )}
      </span>
    </div>
  );
}

function BackdropAura() {
  // Slow, low-amplitude blob behind the glass so the backdrop blur has
  // perceptible content to refract.
  const frame = useCurrentFrame();
  const t = frame / 60;
  const x = 50 + Math.sin(t) * 20;
  const y = 50 + Math.cos(t * 0.7) * 15;
  return (
    <div
      style={{
        position: "absolute",
        inset: 0,
        pointerEvents: "none",
        background: `radial-gradient(circle at ${x}% ${y}%, rgba(56,189,248,0.22), transparent 50%), radial-gradient(circle at ${100 - x}% ${100 - y}%, rgba(168,85,247,0.18), transparent 55%)`,
      }}
    />
  );
}

