                  alignItems: "baseline",
                  justifyContent: "center",
                  gap: 18,
                  opacity: countIn.opacity,
                  filter: countIn.blur > 0 ? `blur(${countIn.blur}px)` : "none",
                  transform: `translateY(${countIn.translateY}px) scale(${revealScale})`,
                }}
              >
                <span
                  style={{
                    fontFamily: FONT_FAMILY,
                    fontSize: countNum,
                    fontWeight: 800,
                    color: t.fg,
                    letterSpacing: "-0.03em",
