                <span
                  style={{
                    fontFamily: FONT_FAMILY,
                    fontSize: countLabel,
                    fontWeight: 500,
                    color: t.fgMuted,
                    lineHeight: 1,
                  }}
                >
                  Followers
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <Confetti
        startFrame={confettiStart}
        originX={0.5}
        originY={0.5}
        colors={confettiColors}
        particleCount={160}
      />
    </AbsoluteFill>
  );
}

